  const keyboard = {
    inline_keyboard: [
      options.map((_, i) => ({ text: `${i + 1}`, callback_data: `sel_${chatId}_${rIdx}_${i + 1}` })),
      [{ text: '🔄 Nouvelles options', callback_data: `sel_${chatId}_${rIdx}_regen` }]
